#include "portal/portal_html.hpp"

const char *portal_style = R"PORTAL_STYLE(
body {
        margin: 0;
        padding: 0;
        background-color: #000;
        color: #fff;
        font-family: Arial, sans-serif;
        display: flex;
        flex-direction: column;
        height: 100vh;
    }

    .top-bar {
        display: flex;
        align-items: center;
        padding: 10px 20px;
        background-color: #111;
        border-bottom: 1px solid #333;
    }

    .logo-small {
        width: 32px;
        height: 32px;
        margin-right: 10px;
    }

    .title {
        font-size: 20px;
        font-weight: bold;
    }

    .content {
        flex: 1;
        display: flex;
        flex-direction: column;
        justify-content: center;
        align-items: center;
        padding: 20px;
        text-align: center;
    }

    .logo-large {
        width: 120px;
        height: 120px;
        margin-bottom: 30px;
    }

    select, input {
        width: 80%;
        max-width: 300px;
        padding: 10px;
        margin: 10px 0;
        border-radius: 5px;
        border: none;
        font-size: 16px;
    }

    .button {
        width: 80%;
        max-width: 300px;
        padding: 12px;
        margin-top: 20px;
        background-color: #1e90ff;
        border: none;
        border-radius: 5px;
        color: white;
        font-size: 18px;
        cursor: pointer;
    }
)PORTAL_STYLE";

const char *portal_body = R"PORTAL_BODY(
<div class="top-bar">
    <svg class="logo-small"><use href="#logo"/></svg>
    <div class="title">AmbientZero</div>
</div>

<div class="content">
    <svg class="logo-large"><use href="#logo"/></svg>

    <h2>Wi‑Fi Setup</h2>

    <!-- ⭐ REAL FORM, NO JAVASCRIPT -->
    <form method="POST" action="/save">

        <select name="ssid" id="wifiList">
            <!-- WIFI_OPTIONS -->
        </select>

        <input name="password" class="input-field" type="password" placeholder="Password">

        <button class="button" type="submit">Save</button>
    </form>
</div>
)PORTAL_BODY";

